const dr = $json.domain_rating;

let authority_score = 0;

if (dr >= 80) {
  authority_score = 90;
}
else if (dr >= 60) {
  authority_score = 75;
}
else if (dr >= 40) {
  authority_score = 60;
}
else if (dr >= 20) {
  authority_score = 40;
}
else {
  authority_score = 20;
}

let link_type = $json.nofollow
  ? "NOFOLLOW"
  : "DOFOLLOW";

let opportunity_score = authority_score;

if (!($json.nofollow)) {
  opportunity_score += 10;
}

opportunity_score = Math.min(opportunity_score, 100);

return {
  ...$json,

  authority_score,

  opportunity_score,

  link_type
};
